import { ThemeToggle } from '@/components/theme-toggle';
import { getProjects } from '@backend/services/db/project-service';
import { createClient } from '@shared/utils/supabase/server';
import SignOutButton from './SignOutButton';
import { SideNav } from '@/components/layout/side-nav';
import { TopNav } from '@/components/layout/top-nav';
import { LayoutDashboard, Rocket } from 'lucide-react';

export default async function DashboardLayout({ children }: { children: React.ReactNode }) {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    const allProjects = user ? await getProjects(user.id) : [];
    const activeWorkflows = allProjects.filter(p => !p.is_demo_project);

    const mainItems = [
        { title: 'Dashboard', href: '/dashboard', icon: <LayoutDashboard className="w-4 h-4" /> },
        { title: 'New Kickoff', href: '/kickoff', icon: <Rocket className="w-4 h-4" /> }
    ];

    return (
        <div className="flex min-h-screen bg-background">
            <div className="hidden md:block sticky top-0 h-screen overflow-y-auto">
                <SideNav mainItems={mainItems} projects={activeWorkflows} />
            </div>

            {/* Main Content Area */}
            <main className="flex-1 flex flex-col min-w-0">
                <TopNav>
                    <div className="flex items-center gap-4">
                        <div className="hidden md:flex flex-col items-end">
                            <span className="text-sm font-semibold truncate max-w-[150px]">{user?.email?.split('@')[0] || 'User'}</span>
                            <span className="text-[10px] uppercase tracking-widest text-muted-foreground font-bold">Operator</span>
                        </div>
                        <ThemeToggle />
                        <SignOutButton />
                    </div>
                </TopNav>
                <div className="p-6 md:p-8 w-full max-w-[1600px] mx-auto animate-in fade-in duration-500">
                    {children}
                </div>
            </main>
        </div>
    );
}
